 6→class CoroutinesJvmTest : TestBase() {
 7→    @Test
 8→    fun testNotCancellableCodeWithExceptionCancelled() = runTest(expected = {e -> e is TestException}) {
 9→        expect(1)
10→        // CoroutineStart.ATOMIC makes sure it will not get cancelled for it starts executing
11→        val job = launch(start = CoroutineStart.ATOMIC) {
12→            Thread.sleep(100) // cannot be cancelled
13→            throwTestException() // will throw
14→            expectUnreached()
15→        }
16→        expect(2)
17→        job.cancel()
18→        finish(3)
19→    }
20→
21→    @Test
22→    fun testCancelManyCompletedAttachedChildren() = runTest {
23→        val parent = launch { /* do nothing */ }
24→        val n = 10_000 * stressTestMultiplier
25→        repeat(n) {
26→            // create a child that already completed
27→            val child = launch(start = CoroutineStart.UNDISPATCHED) { /* do nothing */ }
28→            // attach it manually via internal API
29→            @Suppress("DEPRECATION_ERROR")
30→            parent.attachChild(child as ChildJob)
31→        }
32→        parent.cancelAndJoin() // cancel parent, make sure no stack overflow
33→    }
34→
35→    private fun throwTestException(): Unit = throw TestException()
36→}

