import org.junit.Test
import kotlin.test.assertEquals

class EventLoopYieldTest : TestBase() {

    @Test
    fun testYieldYieldsToDelayedTask() {
        val list = ArrayList<Int>()
        runBlocking {
            launch {
                delay(1)
                list.add(1)
            }
            Thread.sleep(100) // Wait for delayed task to be ready
            yield()
            list.add(2)
        }
        assertEquals(listOf(1, 2), list)
    }
}
"}

