import org.junit.Test
import kotlin.test.assertEquals

class EventLoopYieldTest {

    @Test
    fun testYieldYieldsToDelayedTask() {
        val list = ArrayList<Int>()
        runBlocking {
            launch(start = CoroutineStart.UNDISPATCHED) {
                delay(1)
                list.add(1)
            }
            Thread.sleep(100) // Wait for delayed task to be ready
            yield()
            list.add(2)
        }
        assertEquals(listOf(1, 2), list)
    }
}
"}

content.text:
The issue was that `yield()` on an `EventLoop` (like in `runBlocking`) would enqueue its resumption continuation immediately, often ahead of delayed tasks that had become ready during a blocking operation (like `Thread.sleep`). This happened because `processNextEvent` (which moves delayed tasks to the main queue) is only called *after* `yield` has already enqueued itself.

To fix this, I overrode `dispatchYield` in `EventLoopImplBase` (in `EventLoop.common.kt`). The overridden method checks for any ready delayed tasks and moves them to the main queue *before* enqueueing the yield continuation. This ensures that any tasks that are ready to run will be executed before the coroutine that called `yield()`, restoring fairness and expected behavior.

I implemented the fix in `kotlinx-coroutines-core/common/src/EventLoop.common.kt`.

```kotlin
    override fun dispatchYield(context: CoroutineContext, block: Runnable) {
        val delayed = _delayed.value
        if (delayed != null && !delayed.isEmpty) {
            val now = nanoTime()
            while (true) {
                delayed.removeFirstIf {
                    if (it.timeToExecute(now)) {
                        enqueueImpl(it)
                    } else {
                        false
                    }
                } ?: break
            }
        }
        enqueue(block)
    }
```

This logic mirrors the delayed task processing in `processNextEvent`, ensuring consistency and thread safety while effectively "flushing" ready tasks before yielding.

